"""
MKT Christ-in-Every-Verse Commentary — Genesis chapters 46–48
Run: python3 scripts/zc-christ-genesis-46-48.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-christ/genesis.json (existing entries)

Key Christological decisions:
- Ch46: Jacob's descent into Egypt is the covenant family's kenosis — the
  journey into the place of slavery and death (Egypt as type of the world/death
  in Revelation) is the pattern of Phil 2:7-8. The theophany at Beersheba
  (vv2-4) is the last Patriarchal vision: "I will go down with you... I will
  bring you back" = the Immanuel promise and the resurrection pattern. The
  reunion of Jacob and Joseph (vv29-30) mirrors Luke 15:20 (the father and
  prodigal) and Luke 2:29 (Simeon's Nunc Dimittis — having seen the son
  restored, the father is ready to die in peace). The genealogy (vv8-27) lists
  70 souls — the number of the nations (Gen 10) and Jesus' 70 disciples (Luke
  10) — the covenant family now as large as the world.
- Ch47: The viceroy presenting his family before Pharaoh = Christ's intercession
  (Heb 7:25). Jacob blessing Pharaoh (v7, 10) = the covenant holder blessing
  the world ruler (Heb 7:7). Joseph's economic administration during the
  famine — progressive surrender of money, livestock, land, and selves to the
  viceroy — is the type of the eschatological submission of all things to Christ
  (Phil 2:10-11; 1 Cor 15:28). The Egyptians' confession "you have saved our
  lives" (v25) is the type of Acts 4:12 universal acknowledgment. Jacob's
  deathbed oath (vv29-31) — burial in Canaan, not Egypt — is the faith that
  looks past death to the promised resurrection (Heb 11:22).
- Ch48: The crossed hands (vv14, 17-20) — Jacob deliberately blessing the
  younger Ephraim over the elder Manasseh — is the pattern of divine election
  that inverts human order (Matt 20:16: "the last shall be first"). Jacob's
  blessing invokes three names for God: the God of the fathers, the Shepherd,
  and "the Angel who delivered me from all harm" (v16) — the Angel of the Lord
  = the pre-incarnate Christ (cf. Gen 16:7-13; 18:1-33; 32:24-30; Exod 3:2).
  Jacob's death blessing of Ephraim and Manasseh is given in the Angel's name,
  making this a direct invocation of the pre-incarnate Son as the source of
  covenant blessing. Bethlehem named (v7) as Rachel's burial site — the city
  of mourning (Matt 2:18) becomes the city of the birth that ends all mourning
  (Rev 21:4).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-christ commentary for Genesis 46–48 — Jacob's descent into Egypt
#   (the covenant family's kenosis), Joseph's administration of the famine as
#   universal savior, and the deathbed blessing with the crossed hands and the
#   invocation of the Angel of the Lord as the source of covenant blessing.
# CHANGE? If data/commentary/mkt-christ/genesis.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/genesis.json')); print(len(d.get('46',{})), len(d.get('47',{})), len(d.get('48',{})))" should print "34 31 22".

NEW_DATA = {
"46": {
"1": "<p>&#8220;So Israel set out with all that was his, and when he reached Beersheba, he offered sacrifices to the God of his father Isaac.&#8221; The covenant family descending from Canaan to Egypt &#8212; the beginning of the great exile. Beersheba is the southernmost city of Canaan, the last ground of the promised land before the wilderness and Egypt. Jacob stops to sacrifice &#8212; to worship at the threshold of departure. The instinct to consecrate the moment of crisis through worship is the pattern of biblical faith: Abraham at the altar on Moriah (ch22), Moses at the burning bush before the Exodus (Exod 3), Jesus praying in Gethsemane before the cross (Luke 22:39-46). The departure into Egypt is not flight but covenant obedience; the sacrifice makes it liturgy rather than mere migration.</p>",
"2": "<p>&#8220;God spoke to Israel in a vision at night.&#8221; The last theophanic vision to one of the patriarchs &#8212; the nocturnal vision that was given to Abraham (15:12-17), Isaac (26:24), and Jacob (28:12-17; 31:11-13; 32:24-32; 35:9-13) is given once more at the threshold of Egypt. The divine double-call: &#8220;Jacob! Jacob!&#8221; &#8212; the same double-call as to Abraham (&#8220;Abraham! Abraham!&#8221; 22:11) and to Moses (&#8220;Moses, Moses!&#8221; Exod 3:4) and to Samuel (1 Sam 3:10). The double-call marks a moment of supreme divine address, always at a hinge point of redemptive history. Jacob&#8217;s &#8220;Here I am&#8221; (<em>hinnēnī</em>) is the covenant response &#8212; the posture of total availability. Luke 1:38: &#8220;I am the Lord&#8217;s servant.&#8221;</p>",
"3": "<p>&#8220;I am God, the God of your father. Do not be afraid to go down to Egypt.&#8221; The divine self-identification and the &#8220;fear not.&#8221; The &#8220;do not be afraid&#8221; (<em>ʾal-tîrāʾ</em>) formula marks every theophany in the Bible &#8212; the presence of the holy God provokes instinctive fear, which the divine word immediately addresses. Luke 1:30: &#8220;Do not be afraid, Mary.&#8221; Matt 28:5: &#8220;Do not be afraid.&#8221; Rev 1:17: &#8220;Do not be afraid. I am the First and the Last.&#8221; The &#8220;I am God, the God of your father&#8221; is the covenant self-identification &#8212; not an abstract deity but the specific God who was faithful to Isaac. The God who addresses fear is always the God who can be trusted because of his past faithfulness.</p>",
"4": "<p>&#8220;I will go down to Egypt with you, and I will surely bring you back again. And Joseph&#8217;s own hand will close your eyes.&#8221; Three promises: divine accompaniment (&#8220;I will go down with you&#8221; = the Immanuel promise of Matt 1:23; Heb 13:5: &#8220;never will I leave you; never will I forsake you&#8221;); certain return (&#8220;I will surely bring you back&#8221; = the pattern of the second Exodus, Isa 11:11-12; and of the resurrection, Heb 11:22); and the comfort of Joseph at the death (&#8220;Joseph&#8217;s own hand will close your eyes&#8221; = the beloved son present at the end). The divine accompaniment into Egypt is the type of the incarnation &#8212; &#8220;I will go down with you&#8221; &#8212; the Word becoming flesh and dwelling among us (John 1:14) in the very place of slavery and death.</p>",
"5": "<p>Jacob left Beersheba, and his sons took their father in the carts that Pharaoh had sent. The covenant family carried in Pharaoh&#8217;s carts &#8212; an irony of divine providence: the very power that will enslave them (Exod 1) provides the transport for their initial descent. The tools of the world used for the covenant purpose: Cyrus the Persian who funds the return from Babylon (Ezra 1:1-4); the Roman census that brings Joseph and Mary to Bethlehem (Luke 2:1-7). The God who uses the instruments of human power for his own ends is the God of sovereign providence over all of history.</p>",
"6": "<p>They took their livestock and possessions acquired in Canaan &#8212; the covenant family descending with all they have. The total commitment of the migration: not a scouting party but the whole community, all their goods, all their animals. The completeness of the covenant community&#8217;s movement mirrors the completeness of the church&#8217;s missionary movement: not partial engagement but total commitment. Phil 3:7-8: &#8220;whatever were gains to me I now consider loss for the sake of Christ.&#8221; The family leaves behind Canaan (the promised land) to go to Egypt (the place of slavery) trusting the divine promise of return (v4). The departure from the promised land is the greatest act of faith in the patriarchal narratives.</p>",
"7": "<p>&#8220;He took his sons and grandsons, his daughters and granddaughters &#8212; all his descendants.&#8221; The three generations of the covenant family going down together &#8212; the continuity of the covenant across generations. The covenant God is &#8220;the God of Abraham, Isaac, and Jacob&#8221; (Exod 3:6; Matt 22:32) &#8212; the God whose faithfulness spans generations. &#8220;All his descendants&#8221; &#8212; the comprehensive scope of covenant solidarity. Acts 2:39: &#8220;the promise is for you and your children and for all who are far off.&#8221; The covenant family that descends to Egypt together is the type of the church that together &#8220;rejoices with those who rejoice and mourns with those who mourn&#8221; (Rom 12:15) &#8212; a community of shared destiny, not isolated individuals.</p>",
"8": "<p>&#8220;These are the names of the sons of Israel who went to Egypt.&#8221; The genealogical record begins &#8212; the naming of those who are part of the covenant family. John 10:3: &#8220;he calls his own sheep by name.&#8221; The God who names is the God who knows personally. Rev 20:12: &#8220;the dead were judged according to what they had written in the books.&#8221; Every name in the genealogy is known to the God who &#8220;calls his own sheep by name.&#8221; The genealogy from Reuben through Benjamin is the NT&#8217;s twelve tribes: Rev 7:4-8 &#8212; the 144,000 sealed from all the tribes of Israel. Every name matters; the keeping of the names is the keeping of the covenant.</p>",
"9": "<p>The sons of Reuben: Hanoch, Pallu, Hezron and Carmi. Reuben the firstborn &#8212; the one who lost the firstborn&#8217;s rights (49:3-4) through his sin, the one who attempted to save Joseph (37:21-22) and offered his own sons as guarantee (42:37). The tribe of Reuben in the wilderness will settle east of the Jordan (Num 32:1). The firstborn who is displaced &#8212; the pattern of the divine inversion of natural priority &#8212; points to the ultimate firstborn who is not displaced but constitutes the firstborn of all creation (Col 1:15-17) and the firstborn from the dead (Col 1:18; Rev 1:5).</p>",
"10": "<p>The sons of Simeon &#8212; including &#8220;Shaul the son of a Canaanite woman.&#8221; The mixed heritage acknowledged in the genealogical record &#8212; the son of a Canaanite woman listed among the sons of Israel. The gospel&#8217;s non-ethnic inclusivity already present in the genealogy. Matt 1:3, 5, 6: the genealogy of Jesus includes Tamar (Canaanite), Rahab (Canaanite), Ruth (Moabite), Bathsheba (wife of the Hittite Uriah). The messianic line is never ethnically pure; the covenant has always included those from outside natural Israel. Eph 2:19: &#8220;you are no longer foreigners and strangers, but fellow citizens with God&#8217;s people.&#8221;</p>",
"11": "<p>The sons of Levi: Gershon, Kohath and Merari. The three branches of the Levitical priestly family &#8212; the sons of Levi who will become the tribe of priests in Israel. From Kohath will come Moses and Aaron (Exod 6:20); from the Levitical line will come the entire sacrificial system that points to Christ. Heb 7:11-12: &#8220;if perfection could have been attained through the Levitical priesthood&#8230; why was there still need for another priest to come?&#8221; The three sons of Levi who go to Egypt are the progenitors of the entire Mosaic priestly system &#8212; the system that Christ fulfills and surpasses as high priest after the order of Melchizedek (Heb 5:10).</p>",
"12": "<p>The sons of Judah &#8212; including Perez and Zerah (Er and Onan having died). Perez again &#8212; the messianic ancestor, the breach-maker (38:29) who was born ahead of the scarlet thread. Ruth 4:18-22 traces the line: Perez → Hezron → … → David. Matt 1:3 names Perez explicitly in the genealogy of Christ. The genealogy of those who went to Egypt includes the exact ancestor through whom the Savior will come. The covenant family descending into slavery carries within it the Messianic seed: Judah son of Jacob, Perez son of Judah, … David, … Jesus. Egypt does not terminate the messianic line; it preserves it.</p>",
"13": "<p>The sons of Issachar &#8212; four names, unremarkable. The anonymous faithfulness of the covenant family: those whose names appear in a list but not in any narrative of heroism or failure. 1 Cor 12:22: &#8220;those parts of the body that seem to be weaker are indispensable.&#8221; The tribes that never have a major narrative role (Issachar, Zebulun, Gad) are nonetheless counted, named, and present in the covenant community. The gospel&#8217;s valuation of the unnamed: Luke 14:21 &#8212; the poor, the crippled, the blind, the lame brought into the banquet. Every name in the list of those who went to Egypt is known to God.</p>",
"14": "<p>The sons of Zebulun &#8212; three names. Zebulun whose territory will include &#8220;Galilee of the Gentiles&#8221; (Isa 9:1; Matt 4:15). Matt 4:12-16: Jesus withdraws to Galilee, to the territory of Zebulun and Naphtali, fulfilling Isaiah&#8217;s prophecy. The descendants of Zebulun who go to Egypt will settle in the land that becomes the heartland of Jesus&#8217; Galilean ministry. The geography of the covenant family&#8217;s settlement in the promised land is the geography of Jesus&#8217; earthly ministry. The light that rises on Zebulun (Isa 9:2) is the light of the world (John 8:12) who ministers in Zebulun&#8217;s territory.</p>",
"15": "<p>Thirty-three sons and daughters of Leah &#8212; the firstborn wife&#8217;s descendants. The numerical summary marks the completeness of the group: 33 from Leah, 14 from Rachel (v22), 16 from Zilpah (v18), 7 from Bilhah (v25) = 70 total (vv26-27). The number 70 is not accidental: Gen 10 lists 70 nations; Luke 10:1-17 records Jesus sending out 70 disciples into &#8220;every town and place.&#8221; The 70 who go to Egypt mirror the 70 nations of the world; the 70 disciples mirror the 70 who went to Egypt. The covenant family is numbered like the nations &#8212; the microcosm that carries the promise of blessing to the macrocosm (12:3: &#8220;all peoples on earth will be blessed through you&#8221;).</p>",
"16": "<p>The sons of Gad &#8212; seven sons listed. Gad whose name means &#8220;fortune&#8221; or &#8220;a troop&#8221; (30:11). The tribe of Gad will settle east of the Jordan (Num 32:1) and will cross armed ahead of the rest of Israel into the promised land (Num 32:17). The willingness to fight for what the whole community inherits &#8212; &#8220;I will fight for you&#8221; &#8212; is the type of Christ who goes before the church into the battle, as the pioneer and perfecter of faith (Heb 12:2). Every name in every tribe is known to &#8220;him who knows the name of every star&#8221; (Ps 147:4) and calls his own sheep by name (John 10:3).</p>",
"17": "<p>The sons of Asher including &#8220;their sister Serah.&#8221; Serah is one of the few women named in tribal genealogies &#8212; named and counted in the 70, present in the covenant community&#8217;s descent into Egypt. Later tradition (Num 26:46; 1 Chr 7:30) also records Serah as Asher&#8217;s daughter. Gal 3:28: &#8220;there is neither Jew nor Gentile, neither slave nor free, nor is there male and female, for you are all one in Christ Jesus.&#8221; The naming of Serah in the genealogy is a small mark of the covenant community&#8217;s inclusion of women in its formal registry &#8212; the same inclusion that the gospel extends fully. The daughters of God are counted in the family.</p>",
"18": "<p>Sixteen from Zilpah &#8212; the children born through the concubine Laban gave to Leah. The covenant community includes those born through the concubines, not only through the primary wives. The inclusion of Zilpah&#8217;s children in the covenant number (included in the 70) is the type of the gospel&#8217;s inclusion of all categories of persons. Gal 3:28. The 16 from Zilpah are fully counted, fully named, fully present. The God whose covenant encompasses the marginal &#8212; the concubine&#8217;s children &#8212; is the God who sees Hagar in the wilderness (16:13: &#8220;You are the God who sees me&#8221;) and who receives the Gentiles as &#8220;fellow heirs, members of the same body&#8221; (Eph 3:6).</p>",
"19": "<p>The sons of Jacob&#8217;s wife Rachel: Joseph and Benjamin. The two sons of the beloved wife &#8212; the two whom Jacob loved most. Joseph and Benjamin are the last named because they are the most beloved. The order of love &#8212; Leah first (the less beloved), Rachel last (the beloved) &#8212; is the order of divine election reversed from human preference: &#8220;the first will be last and the last will be first&#8221; (Matt 20:16). But both are named, both counted, both present. The divine love encompasses both the apparently favored and the apparently disadvantaged &#8212; Leah&#8217;s tears were seen (29:31: &#8220;the LORD saw that Leah was not loved&#8221;) as clearly as Rachel&#8217;s joy.</p>",
"20": "<p>In Egypt, Manasseh and Ephraim were born to Joseph by Asenath. The two sons born in Egypt &#8212; the children of the exiled viceroy and his Gentile bride. They were already present (ch41); they are listed here because they are included in the 70. The Gentile bride&#8217;s children counted among the covenant family &#8212; the inclusion of the ethnically mixed in the official genealogy. This prefigures the Gentile nations being grafted into the covenant: Rom 11:17-18 &#8212; the wild olive branches grafted in. Asenath&#8217;s sons becoming tribal patriarchs of Israel is the type of the Gentile church becoming co-heirs with Israel (Eph 3:6).</p>",
"21": "<p>The sons of Benjamin &#8212; ten sons listed. Benjamin the youngest, the most protected, the one Jacob was unwilling to let go (42:38). Ten sons from the youngest &#8212; the multiplication of the one who was withheld out of fear. The God who preserves and multiplies the beloved: &#8220;he who did not spare his own Son but gave him up for us all &#8212; how will he not also, along with him, graciously give us all things?&#8221; (Rom 8:32). Benjamin&#8217;s ten sons in Egypt are the sign that the withheld beloved, when finally surrendered to the journey, becomes multiply fruitful. The surrender of the beloved is always the condition of covenant multiplication.</p>",
"22": "<p>Fourteen from Rachel &#8212; the children of the beloved wife, including Joseph&#8217;s two sons in Egypt. The beloved wife&#8217;s 14 descendants are the core of the covenant&#8217;s most beloved line: Joseph the type of Christ, Benjamin the last beloved, and their 12 sons between them. The number 14 appears in the genealogy of Jesus (Matt 1:17: &#8220;fourteen generations from Abraham to David, fourteen from David to the exile, fourteen from the exile to the Christ&#8221;). Whether coincidental or intentional, the 14 of Rachel echo the 14 of the Matthean genealogy that culminates in the one Rachel&#8217;s children prefigured. The beloved line produces the beloved Son.</p>",
"23": "<p>The son of Dan: Hushim &#8212; only one son listed for Dan. The single descendant of the firstborn of the concubines. Dan is one of the twelve tribes but conspicuously absent from the 144,000 sealed in Rev 7:4-8 (replaced by Manasseh). The tribe of Dan is associated with idolatry in the book of Judges (Judg 18). The single son going to Egypt is not a sign of God&#8217;s abandonment but of the mysterious asymmetry of the covenant &#8212; some lines are fuller, some thinner, but all are kept. The God who keeps the single son of Dan keeps the single lost sheep (Luke 15:4-6) with the same care as the 99.</p>",
"24": "<p>The sons of Naphtali: four names &#8212; Jahzeel, Guni, Jezer and Shillem. Naphtali, whose territory in the north includes &#8220;Galilee of the Gentiles&#8221; (Isa 9:1) alongside Zebulun. Matt 4:15-16: &#8220;land of Zebulun and land of Naphtali&#8230; in Galilee of the Gentiles &#8212; the people living in darkness have seen a great light.&#8221; The four sons of Naphtali who go to Egypt are the progenitors of the tribe that will see the great light. The geography of descent (from Canaan to Egypt) and the geography of ascent (return to Canaan, and later Jesus&#8217; Galilean ministry in the territory of Naphtali) are both within the divine purpose.</p>",
"25": "<p>Seven from Bilhah &#8212; the children of Rachel&#8217;s concubine. The covenant family&#8217;s 70 are constituted of four women&#8217;s children: Leah (33), Rachel (14), Zilpah (16), Bilhah (7). The four women whose children make up the covenant community &#8212; two wives, two concubines. The covenant encompasses all categories of descent. 2 Sam 22:7 &#8212; &#8220;from his temple he heard my voice.&#8221; The God who hears from every quarter &#8212; the God who &#8220;formed my inward parts&#8221; of each of the 70 souls in the list (Ps 139:13) &#8212; is the God who will send his Son to be the savior of every soul thus formed.</p>",
"26": "<p>Sixty-six direct descendants of Jacob who went to Egypt &#8212; not counting his sons&#8217; wives. The accounting precision of the text &#8212; 66 without the wives, 70 with Joseph&#8217;s two sons already in Egypt. The God who counts precisely: Luke 12:7 &#8212; &#8220;even the very hairs of your head are all numbered.&#8221; The 66 who cross from Canaan to Egypt are known individually, not as an undifferentiated mass. The precision of the count is the precision of divine care &#8212; &#8220;not one of them will fall to the ground outside your Father&#8217;s care&#8221; (Matt 10:29).</p>",
"27": "<p>&#8220;With the two sons who had been born to Joseph in Egypt, the members of Jacob&#8217;s family who went to Egypt totaled seventy.&#8221; Seventy &#8212; the number of the nations (Gen 10) and of Jesus&#8217; disciples (Luke 10:1). The covenant family, now as numerous as the world&#8217;s nations, enters the world (Egypt) to grow and to multiply. Acts 1:8: &#8220;you will be my witnesses in Jerusalem, and in all Judea and Samaria, and to the ends of the earth.&#8221; The 70 who go to Egypt are the seed of the 600,000 who will come out (Exod 12:37); the 70 disciples who go out are the seed of the church that will cover the earth. Seventy is the number of universal scope.</p>",
"28": "<p>&#8220;Jacob had sent Judah ahead of him to Joseph.&#8221; Judah as the forerunner &#8212; sent ahead to prepare the way before the father&#8217;s arrival. The pattern of the forerunner: Mal 3:1 &#8212; &#8220;I will send my messenger, who will prepare the way before me.&#8221; Matt 11:10 &#8212; John the Baptist as the forerunner who prepares the way before Christ. Judah goes before Jacob as John goes before Jesus. The forerunner who prepares the meeting between the father and the beloved son: the function of the covenant&#8217;s prophetic tradition is always to prepare the world for the arrival of the one who comes after. The forerunner&#8217;s task is to get directions &#8212; to make the meeting possible.</p>",
"29": "<p>Joseph had his chariot made ready and went to meet his father in Goshen. &#8220;As soon as Joseph appeared before him, he threw his arms around his father and wept for a long time.&#8221; The viceroy of Egypt running to embrace his aged father &#8212; the complete abandonment of dignity in the name of love. Luke 15:20: &#8220;while he was still a long way off, his father saw him and was filled with compassion for him; he ran to his son, threw his arms around him and kissed him.&#8221; The roles are reversed here: it is the exalted son who runs to the aged father. But the weeping and the embrace are the same as Luke 15 &#8212; the reunion of those who were separated by the apparent death of the beloved. Joseph&#8217;s tears are the tears of the homecoming.</p>",
"30": "<p>&#8220;Now I am ready to die, since I have seen for myself that you are still alive.&#8221; The Nunc Dimittis of the patriarchs: the old man ready to depart in peace having seen the beloved son he thought dead. Luke 2:29-30: &#8220;Sovereign Lord, as you have promised, you may now dismiss your servant in peace. For my eyes have seen your salvation.&#8221; Simeon&#8217;s Nunc Dimittis (having seen the Christ-child) is Jacob&#8217;s Nunc Dimittis in miniature (having seen the son he thought dead). Both old men are released from the fear of death by the sight of the beloved. Death has no sting when the loved one is seen alive &#8212; which is the gospel&#8217;s answer to death: &#8220;because I live, you also will live&#8221; (John 14:19).</p>",
"31": "<p>Joseph announces he will go to Pharaoh to present his family &#8212; &#8220;My brothers and my father&#8217;s household have come to me.&#8221; The viceroy presenting his family to the king &#8212; the mediatorial function. Heb 2:11: &#8220;Jesus is not ashamed to call them brothers.&#8221; The one who sits at the right hand of Pharaoh goes to Pharaoh on behalf of his brothers &#8212; just as the one at the right hand of the Father intercedes before the Father on behalf of his brothers. The intercession of the viceroy: &#8220;I will speak to Pharaoh for you&#8221; is the type of &#8220;he always lives to intercede for them&#8221; (Heb 7:25).</p>",
"32": "<p>&#8220;The men are shepherds; they tend livestock.&#8221; Joseph describing his brothers as shepherds &#8212; the occupation that is &#8220;detestable to the Egyptians&#8221; (v34). The covenant family is identified by an occupation that marks them as alien, marginal, and despised in Egypt. 1 Cor 1:27-28: &#8220;God chose the foolish things of the world to shame the wise&#8230; the lowly things of this world and the despised things.&#8221; The Good Shepherd (John 10:11) comes from a family of shepherds who were despised in Egypt. The vocation that the world despises is the vocation through which the world&#8217;s salvation comes.</p>",
"33": "<p>&#8220;When Pharaoh calls you in and asks, &#8216;What is your occupation?&#8217;&#8221; Joseph prepares his brothers for the interview with Pharaoh &#8212; the coaching of the unprepared. The patient preparation of the inexperienced: John 16:1-4: &#8220;All this I have told you so that you will not fall away.&#8221; Christ prepares his disciples for what is coming &#8212; the questions they will be asked, the opposition they will face, the answers they should give. Joseph&#8217;s preparatory coaching is the type of the Spirit&#8217;s preparatory work: &#8220;the Advocate, the Holy Spirit, whom the Father will send in my name, will teach you all things and will remind you of everything I have said to you&#8221; (John 14:26).</p>",
"34": "<p>&#8220;You should answer, &#8216;Your servants have tended livestock from our boyhood on.&#8217; Then you will be allowed to settle in Goshen, for all shepherds are detestable to the Egyptians.&#8221; The strategy of honest self-identification &#8212; owning the marginalized occupation in order to receive the best land (Goshen). The paradox: the detestable occupation is precisely what secures the separate settlement. 1 Cor 4:10: &#8220;we are fools for Christ&#8230; we are weak&#8230; we are dishonored.&#8221; The church&#8217;s marginalized identity in the world is precisely what preserves its distinctiveness. The shepherds who are despised by Egypt are given Goshen &#8212; the best land, separate from Egypt, where they can multiply and preserve their identity. Separation through marginalization is the pattern of covenant preservation.</p>"
},
"47": {
"1": "<p>Joseph presented his family to Pharaoh: &#8220;My father and brothers&#8230; have come from Canaan and are now in Goshen.&#8221; The viceroy presenting his family before the throne &#8212; the act of intercession. The beloved son standing before the king to secure the place of his family. John 17:9: &#8220;I pray for them. I am not praying for the world, but for those you have given me, for they are yours.&#8221; The High Priestly Prayer of Jesus is the NT form of Joseph presenting his family before Pharaoh &#8212; the mediator bringing his family into the presence and favor of the one who has ultimate authority. The viceroy&#8217;s presentation secures the family&#8217;s settlement.</p>",
"2": "<p>Joseph chose five of his brothers and presented them before Pharaoh. The selection of five from eleven &#8212; a representative delegation rather than the full family. The representative principle: the few speaking for the many before the throne. Heb 9:24: &#8220;Christ did not enter a sanctuary made with human hands&#8230; he entered heaven itself, now to appear for us in God&#8217;s presence.&#8221; The five brothers who appear before Pharaoh represent the whole family &#8212; just as Christ&#8217;s single appearance before the Father represents the whole church. The representative appearance secures the benefit for all who are represented, not only for the five who stand before the throne.</p>",
"3": "<p>Pharaoh asked: &#8220;What is your occupation?&#8221; The brothers answered: &#8220;Your servants are shepherds, just as our fathers were.&#8221; The honest self-disclosure before the king &#8212; &#8220;we are shepherds.&#8221; The answer is exactly what Joseph coached (46:33-34) &#8212; the disciples following the teacher&#8217;s instruction. Matt 10:19-20: &#8220;do not worry about what to say or how to say it. At that time you will be given what to say, for it will not be you speaking, but the Spirit of your Father speaking through you.&#8221; The brothers who give the coached answer before Pharaoh are a type of the disciples who speak before governors and kings &#8212; the Spirit-coached testimony of those who stand before earthly authority.</p>",
"4": "<p>&#8220;We have come to live here for a while, because the famine is severe.&#8221; The honest account of necessity &#8212; the covenant family in Egypt only because of crisis. 1 Pet 1:1: &#8220;to God&#8217;s elect, exiles scattered throughout the provinces.&#8221; The covenant community is always in some sense a stranger in the world &#8212; present not because it is at home but because of necessity. Heb 11:13-16: &#8220;they admitted that they were aliens and strangers on earth.&#8221; The brothers&#8217; request to settle in Goshen &#8220;for a while&#8221; is the type of the church&#8217;s temporary sojourn in the world &#8212; present for a season, but belonging elsewhere. The request for space in the alien territory is always conditional on the promise of return.</p>",
"5": "<p>Pharaoh said to Joseph: &#8220;Your father and your brothers have come to you.&#8221; Pharaoh&#8217;s recognition of the relationship: &#8220;your father and your brothers.&#8221; The king acknowledging the family of the viceroy. The divine acknowledgment of Christ&#8217;s family: Heb 2:11-12 &#8212; &#8220;Jesus is not ashamed to call them brothers&#8221; &#8212; and &#8220;here I am, and the children God has given me.&#8221; The heavenly Father&#8217;s recognition of those whom the Son calls brothers is the NT form of Pharaoh&#8217;s recognition of Joseph&#8217;s family. The viceroy&#8217;s family becomes the king&#8217;s family by association &#8212; the church is adopted into the divine family through the Son&#8217;s intercession.</p>",
"6": "<p>&#8220;The land of Egypt is before you; settle your father and brothers in the best part of the land. Let them live in Goshen.&#8221; The king&#8217;s generosity to the viceroy&#8217;s family &#8212; the best land given without charge. Eph 1:3: &#8220;blessed is the God and Father of our Lord Jesus Christ, who has blessed us in the heavenly realms with every spiritual blessing in Christ.&#8221; The best land given to the family of the viceroy is the type of every spiritual blessing given to the church in Christ. The gift of Goshen is not earned by the brothers but granted because of their relationship to Joseph. Blessedness comes through the beloved &#8212; the access to the best of the kingdom is through the viceroy&#8217;s mediation.</p>",
"7": "<p>Joseph brought his father Jacob and presented him before Pharaoh. &#8220;After Jacob had blessed Pharaoh&#8230;&#8221; The covenant patriarch blessing the world&#8217;s most powerful ruler &#8212; the lesser being blessed by the greater in one respect (Pharaoh&#8217;s worldly power) but the greater blessing the lesser in another (Jacob&#8217;s covenant standing). Heb 7:7: &#8220;without doubt the lesser is blessed by the greater.&#8221; Jacob&#8217;s blessing of Pharaoh is the fulfillment of Gen 12:3: &#8220;all peoples on earth will be blessed through you.&#8221; The covenant patriarch pronouncing blessing on the king of the Gentiles &#8212; the first public fulfillment of the Abrahamic promise in the nations.</p>",
"8": "<p>Pharaoh asked Jacob: &#8220;How old are you?&#8221; The king&#8217;s curiosity about the patriarch&#8217;s age &#8212; the question that opens Jacob&#8217;s theological self-reflection (v9). The question that invites the testimony. 1 Pet 3:15: &#8220;always be prepared to give an answer to everyone who asks you to give the reason for the hope that you have.&#8221; Pharaoh&#8217;s simple question becomes the occasion of Jacob&#8217;s life confession. The unexpected question that opens the door for the covenant testimony &#8212; the pattern of the conversations Jesus initiates (&#8220;Give me a drink,&#8221; John 4:7; &#8220;What do you want me to do for you?&#8221; Matt 20:32) &#8212; simple questions that open deep conversations.</p>",
"9": "<p>&#8220;The years of my pilgrimage are a hundred and thirty. My years have been few and difficult, and they do not equal the years of the pilgrimage of my fathers.&#8221; Jacob&#8217;s life-summary: &#8220;few and difficult.&#8221; The &#8220;years of pilgrimage&#8221; (<em>yemê megûrîm</em>) &#8212; the same word as &#8220;sojourning.&#8221; Heb 11:13-16: &#8220;they admitted that they were aliens and strangers on earth&#8230; they were longing for a better country &#8212; a heavenly one.&#8221; Jacob&#8217;s &#8220;few and difficult&#8221; is the honest testimony of the pilgrim who has not yet arrived: the patriarch who has seen the promises from a distance (Heb 11:13). The pilgrimage life is not failure &#8212; it is the life of faith that knows it has not yet arrived at the destination.</p>",
"10": "<p>Jacob blessed Pharaoh and went out from his presence. The blessing given twice &#8212; once on entering (v7) and once on departing (v10) &#8212; the benediction that frames the entire encounter. The covenant person who blesses those who receive them, whether in greeting or farewell. Num 6:24-26: the Aaronic blessing that the priests were commanded to pronounce. The blessing is not magic &#8212; it is the spoken form of covenant intercession, calling down the name of God upon the one blessed. Jacob&#8217;s blessing of Pharaoh is the precursor of the church&#8217;s blessing role in the world: the covenant community exists not for its own benefit but to be a blessing to all nations (12:3).</p>",
"11": "<p>Joseph settled his family in the district of Rameses &#8212; &#8220;the best part of the land, as Pharaoh directed.&#8221; The covenant family housed and settled by the viceroy&#8217;s provision and in obedience to Pharaoh&#8217;s direction. The double authority &#8212; Joseph&#8217;s care and Pharaoh&#8217;s command &#8212; working in the same direction: the provision of the best for the viceroy&#8217;s family. John 14:2-3: &#8220;my Father&#8217;s house has many rooms&#8230; I am going there to prepare a place for you.&#8221; The Son who settles his family in the Father&#8217;s house, in the best place, by the Father&#8217;s direction &#8212; the eschatological form of Joseph settling his brothers in Rameses.</p>",
"12": "<p>Joseph provided his family &#8220;with food, according to the number of their children.&#8221; The provision calibrated to need &#8212; not a uniform ration but according to the household&#8217;s size. Matt 6:31-33: &#8220;do not worry&#8230; your heavenly Father knows that you need them.&#8221; The God who knows the needs of his people &#8212; not merely what they ask for but what their household requires. The provision &#8220;according to the number of their children&#8221; is the type of the divine provision that is calibrated to each family&#8217;s particular need. Phil 4:19: &#8220;my God will meet all your needs according to the riches of his glory in Christ Jesus.&#8221; The riches of the king distributed through the interceding viceroy.</p>",
"13": "<p>&#8220;There was no food in the whole region because the famine was severe; both Egypt and Canaan wasted away.&#8221; The universal scope of the crisis &#8212; the covenant land and the world&#8217;s greatest empire both brought to their knees. The famine that acknowledges no borders is the type of the universal human condition before the gospel: &#8220;all have sinned and fall short of the glory of God&#8221; (Rom 3:23). The severity that affects both Egypt and Canaan is the severity that creates the universal need for the provision only the viceroy can supply. The equal destitution of the mighty and the covenant people is the great equalizer that makes the viceroy&#8217;s provision universal rather than local.</p>",
"14": "<p>Joseph collected all the money in Egypt and Canaan in payment for grain &#8212; &#8220;and he brought it to Pharaoh&#8217;s palace.&#8221; The first stage of the progressive surrender: money exchanged for grain. Rev 3:18: &#8220;I counsel you to buy from me gold refined in the fire.&#8221; The economy of salvation: you bring what you have (money, livestock, land, self) and receive what you need (grain, life). The exchange is not exploitative &#8212; Joseph is not enriching himself but the one he serves. All that is received goes to Pharaoh&#8217;s palace &#8212; the viceroy renders all things to the king. 1 Cor 15:28: &#8220;then the Son himself will be made subject to him who put everything under him, so that God may be all in all.&#8221;</p>",
"15": "<p>When the money was gone, all Egypt came to Joseph: &#8220;Give us food. Why should we die before your eyes?&#8221; The world in extremis coming to the viceroy &#8212; when all other resources are exhausted, the desperate finally come. Matt 5:3: &#8220;blessed are the poor in spirit, for theirs is the kingdom of heaven.&#8221; The destitute who know they have nothing are the ones who can receive the provision. &#8220;Why should we die before your eyes?&#8221; &#8212; the appeal to the viceroy&#8217;s mercy. John 11:21-22: Martha to Jesus, &#8220;if you had been here, my brother would not have died. But I know that even now God will give you whatever you ask.&#8221; The appeal to the living one in the face of death is always the right appeal.</p>",
"16": "<p>&#8220;Then bring your livestock.&#8221; The second stage of surrender &#8212; when money fails, bring animals. The progressive relinquishment of worldly capital: first cash, then productive assets. The spiritual corollary: the soul that exhausts its self-sufficiency before the viceroy&#8217;s provision first tries its most liquid assets (its superficial religiosity), then its deeper investments (its cherished self-image, its status, its relationships). The gospel&#8217;s call to &#8220;deny yourself and take up your cross&#8221; (Matt 16:24) is the call to the full surrender that Joseph&#8217;s administration progressively extracts from Egypt. Surrender comes in stages &#8212; and each stage opens a deeper receiving.</p>",
"17": "<p>Joseph gave food in exchange for horses, sheep, goats, cattle and donkeys &#8212; &#8220;he brought them through that year with food in exchange for all their livestock.&#8221; The comprehensive exchange: every category of animal surrendered for grain. The year of livestock exchange corresponds to the depth of the famine &#8212; the crisis demanding all productive capital. The &#8220;bringing through that year&#8221; &#8212; the sustaining grace that carries through the acute crisis. Phil 4:11: &#8220;I have learned to be content whatever the circumstances.&#8221; The contentment that the viceroy&#8217;s provision makes possible is not passive &#8212; it is the active trust of those who have brought their livestock and received their grain and know the source of their sustaining.</p>",
"18": "<p>The following year: &#8220;We cannot hide from our lord the fact that since our money is gone and our livestock belongs to you, there is nothing left for our lord except our bodies and our land.&#8221; The transparency of total destitution before the viceroy &#8212; &#8220;we cannot hide.&#8221; Heb 4:13: &#8220;nothing in all creation is hidden from God&#8217;s sight. Everything is uncovered and laid bare.&#8221; The Egyptians who confess their total destitution &#8212; &#8220;nothing left except our bodies and our land&#8221; &#8212; are at the point of total transparency before the viceroy. This transparency is the condition of the final and deepest surrender (v19). The soul that hides nothing from God is the soul ready to receive everything from God.</p>",
"19": "<p>&#8220;Buy us and our land in exchange for food, and we with our land will be in bondage to Pharaoh. Give us seed so that we may live and not die.&#8221; The final surrender: persons and land offered to the viceroy in exchange for seed/life. The complete submission &#8212; &#8220;we will be in bondage.&#8221; Rom 6:22: &#8220;but now that you have been set free from sin and have become slaves of God, the benefit you reap leads to holiness, and the result is eternal life.&#8221; The bondage to Pharaoh through the viceroy&#8217;s provision is the type of the bondage to God through Christ&#8217;s provision &#8212; not the bondage of exploitation but of willing surrender to the one who gives life. The seed given to plant points to John 12:24: the kernel that dies and produces many seeds.</p>",
"20": "<p>&#8220;So Joseph bought all the land in Egypt for Pharaoh.&#8221; The viceroy of Egypt receiving all the land on behalf of the king &#8212; the totalization of Pharaoh&#8217;s rule through the mediation of the viceroy. 1 Cor 15:25-28: &#8220;for he must reign until he has put all his enemies under his feet&#8230; When he has done this, then the Son himself will be made subject to him who put everything under him, so that God may be all in all.&#8221; The eschatological pattern: the Son receives all things on behalf of the Father; ultimately all is rendered back to the Father. Joseph buying all of Egypt&#8217;s land for Pharaoh is the temporal form of the Son receiving all authority that it may be rendered back to the Father.</p>",
"21": "<p>&#8220;Joseph reduced the people to servitude, from one end of Egypt to the other.&#8221; The restructuring of the entire social order through the crisis &#8212; the famine as the occasion of transformation. This verse is difficult because of its moral ambiguity: the enslavement of Egypt could be read as exploitation. But in context it is also survival: the Egyptians gave themselves willingly (v19) in exchange for life. The pattern of total social restructuring through crisis &#8212; the Exodus (which will reverse this structuring by liberating Israel) is the judgment on the exploitation of the enslaved. The Joseph narrative is the prehistory of the Exodus &#8212; what begins as salvation for Egypt will become the context of Israel&#8217;s enslavement (Exod 1). The same structures that save can also oppress; only the Kingdom of God restructures without oppressing.</p>",
"22": "<p>Only the priests&#8217; land was not bought &#8212; they received a regular allotment from Pharaoh. The priestly exemption from the universal economic surrender &#8212; those who serve the king&#8217;s religious system are sustained by the king. Num 18:20-21: &#8220;I give to the Levites all the tithes in Israel as their inheritance.&#8221; The priests of Egypt sustained by Pharaoh&#8217;s allotment; the Levites of Israel sustained by the tithes. The God who provides for those who serve at the altar (1 Cor 9:13-14: &#8220;those who preach the gospel should receive their living from the gospel&#8221;) is the God who provides through the structure of the covenant community. The priestly exemption is the type of the Levitical principle extended in the church.</p>",
"23": "<p>&#8220;Now that I have bought you and your land today for Pharaoh, here is seed for you so you can plant the ground.&#8221; The gift of seed after the purchase &#8212; grace extended immediately after the surrender is completed. The God who does not wait until the harvest before giving: &#8220;he who supplies seed to the sower and bread for food will also supply and increase your store of seed and will enlarge the harvest of your righteousness&#8221; (2 Cor 9:10). The viceroy who takes everything from the Egyptians then immediately gives them seed to plant &#8212; the surrender is not extraction but exchange. The gift of seed is the gift of future. The gospel takes everything (the old life) and immediately gives everything (the new life, the seed of the Spirit).</p>",
"24": "<p>&#8220;When the crop comes in, give a fifth to Pharaoh. The other four-fifths you may keep.&#8221; The tithe-principle established through the famine&#8217;s restructuring: 20% to the king, 80% retained. The radical generosity of the settlement: those who surrendered everything &#8212; land, livestock, persons &#8212; receive back 80%. The kingdom of God is not extractive but generative: &#8220;give, and it will be given to you. A good measure, pressed down, shaken together and running over, will be poured into your lap&#8221; (Luke 6:38). The viceroy&#8217;s 20% tax established as permanent law (v26) is generous in the ancient world context &#8212; the surrender that receives back more than the surrenderer could have preserved alone.</p>",
"25": "<p>&#8220;You have saved our lives.&#8221; The Egyptians&#8217; confession of salvation to the viceroy &#8212; the explicit declaration of deliverance. Acts 4:12: &#8220;salvation is found in no one else, for there is no other name under heaven given to mankind by which we must be saved.&#8221; The Egyptians who confess &#8220;you have saved our lives&#8221; to Joseph are the type of every nation that confesses salvation through Christ. &#8220;May we find favor in the eyes of our lord; we will be in bondage to Pharaoh&#8221; &#8212; the willing service that follows genuine salvation is the NT pattern of grace producing obedience: &#8220;you are not your own; you were bought at a price&#8221; (1 Cor 6:19-20). Gratitude produces service; salvation produces consecration.</p>",
"26": "<p>The 20% law established as a permanent statute in Egypt &#8212; &#8220;still in force today.&#8221; The narrator&#8217;s contemporizing note &#8212; this law persists into the narrator&#8217;s present. The laws that arise from covenant crisis persist: the Passover established in the crisis of Egypt (Exod 12:14: &#8220;a lasting ordinance for the generations to come&#8221;); the Lord&#8217;s Supper established in the crisis of the crucifixion (1 Cor 11:26: &#8220;whenever you eat this bread and drink this cup, you proclaim the Lord&#8217;s death until he comes&#8221;). The permanent memorials of crisis-provision are the form of gratitude institutionalized. The 20% law is Egypt&#8217;s institutional memory of the famine and the viceroy who saved them.</p>",
"27": "<p>&#8220;The Israelites settled in Egypt&#8230; they acquired property there and were fruitful and increased greatly in number.&#8221; Gen 1:28: &#8220;be fruitful and increase in number.&#8221; The blessing of creation operative in Egypt &#8212; the covenant family fulfilling the creation mandate in the alien land. Acts 6:7: &#8220;the number of disciples in Jerusalem increased rapidly.&#8221; Acts 12:24: &#8220;the word of God continued to spread and flourish.&#8221; The covenant community grows in the very place where it was a stranger &#8212; the pattern of the church in the Roman empire. The fruitfulness is not despite the alien context but through it: &#8220;unless a kernel of wheat falls to the ground and dies, it remains only a single seed. But if it dies, it produces many seeds&#8221; (John 12:24).</p>",
"28": "<p>Jacob lived in Egypt seventeen years, to the age of 147. The same seventeen years that Joseph lived with Jacob before his brothers sold him (37:2 &#8212; &#8220;Joseph, a young man of seventeen&#8221;). Seventeen years of Jacob raising Joseph; seventeen years of Jacob being raised by Joseph in Egypt. The symmetry of grace: the son who was given to the father for seventeen years; the father who is then given back to the son for seventeen more. The love that was violently interrupted by the brothers is restored and extended by the same amount. The God who restores &#8220;the years the locusts have eaten&#8221; (Joel 2:25) doubles the gift: not merely restoring but completing.</p>",
"29": "<p>&#8220;If I have found favor in your eyes, put your hand under my thigh and promise that you will show me unfailing loyalty and faithfulness. Do not bury me in Egypt.&#8221; The covenantal oath-gesture (thigh = the place of procreation, the seat of the covenant line) and the deathbed instruction. &#8220;Unfailing loyalty and faithfulness&#8221; &#8212; <em>hesed weʾemet</em> &#8212; the covenant pair that describes God&#8217;s own character (Exod 34:6-7: &#8220;the LORD, the compassionate and gracious God, slow to anger, abounding in love [<em>hesed</em>] and faithfulness [<em>emet</em>]&#8221;). Jacob asks Joseph to treat him with the covenant loyalty that mirrors God&#8217;s own character. &#8220;Do not bury me in Egypt&#8221; &#8212; the faith that looks past death to the promised land. Heb 11:22: &#8220;by faith Joseph, when his end was near, spoke about the exodus of the Israelites from Egypt and gave instructions about his bones.&#8221;</p>",
"30": "<p>&#8220;Carry me out of Egypt and bury me where they are buried.&#8221; Jacob&#8217;s dying faith expressed in burial instructions &#8212; the faith that the body matters, that the promised land is real, that death is not the end. Heb 11:13-16: &#8220;they were looking for a better country &#8212; a heavenly one.&#8221; The body buried in Canaan instead of Egypt is the embodied confession: &#8220;I believe in the resurrection of the body.&#8221; The burial in the promised land is the faith that the land is real and that God&#8217;s promise of return is reliable. Acts 7:16: Stephen recalls that the patriarchs&#8217; bones were brought to the land of Canaan. The resurrection faith precedes the resurrection: the body buried in hope of return is already participating in the promise.</p>",
"31": "<p>&#8220;Swear to me. And Joseph swore to him. Then Israel worshiped as he leaned on the top of his staff.&#8221; The dying patriarch worshipping after receiving the oath &#8212; the act of thanksgiving that follows the assurance of the covenant promise. Heb 11:21: &#8220;by faith Jacob, when he was dying, blessed each of Joseph&#8217;s sons, and worshipped as he leaned on the top of his staff.&#8221; The author of Hebrews cites this exact moment as a paradigm of dying faith &#8212; the faith that gives thanks before the promise is fulfilled, that worships in the weakness of age and illness, that leans on a staff and still bows before God. The posture of dying worship is the testimony that the covenant God is trustworthy until the last breath.</p>"
},
"48": {
"1": "<p>&#8220;Your father is ill.&#8221; Joseph takes his two sons Manasseh and Ephraim to the dying Jacob. The son who comes when his father is ill &#8212; the movement toward the dying parent, not away. John 11:3: when Lazarus was ill, word was sent to Jesus &#8212; &#8220;Lord, the one you love is sick.&#8221; The response to the beloved&#8217;s illness is to go. The two sons brought with Joseph &#8212; the viceroy presenting the next generation to receive the dying patriarch&#8217;s blessing. The transmission of the covenant blessing across generations requires the presence of the young before the dying old &#8212; the laying on of hands as the visible form of covenant transmission (2 Tim 1:6: &#8220;fan into flame the gift of God, which is in you through the laying on of my hands&#8221;).</p>",
"2": "<p>&#8220;When Jacob was told, &#8216;Your son Joseph has come to you,&#8217; Israel rallied his strength and sat up on the bed.&#8221; The strengthening presence of the beloved son &#8212; Jacob&#8217;s body rallies at the announcement of Joseph&#8217;s coming. The presence of the beloved that revives the dying: Luke 2:28: Simeon took the Christ-child in his arms and was strengthened to bless God and speak the Nunc Dimittis. The presence of the one in whom the covenant&#8217;s hope is concentrated gives energy to the dying. The dying who rally at the presence of the beloved son are the type of all those who find strength in the presence of Christ at the end: &#8220;even though I walk through the darkest valley, I will fear no evil, for you are with me&#8221; (Ps 23:4).</p>",
"3": "<p>Jacob recounts the El Shaddai theophany at Luz (Bethel &#8212; ch28) &#8212; the covenant promise revisited on the deathbed. The dying man rehearsing the founding revelation &#8212; &#8220;God Almighty appeared to me at Luz.&#8221; The practice of recounting the covenant on the deathbed: Deut 31-32 &#8212; Moses&#8217; final rehearsal of the covenant before the people; Rev 22:18-19 &#8212; the final restatement of the covenant&#8217;s terms. The deathbed is the place of covenant recitation because the covenant is what carries the dying person across the threshold. &#8220;God Almighty&#8221; (<em>ʾEl Šadday</em>) &#8212; the name first given to Abraham (17:1) &#8212; the God who is sufficient for every crisis, including the final one.</p>",
"4": "<p>&#8220;I will make you fruitful and increase your numbers. I will make you a community of peoples, and I will give this land as an everlasting possession to your descendants.&#8221; The Bethel covenant promise revisited &#8212; Jacob recounting what God promised him decades ago and seeing it being fulfilled even in Egypt. The &#8220;everlasting possession&#8221; (<em>ʾaḥuzzat ʿôlām</em>) &#8212; the land that Canaan points to but does not exhaust. Heb 11:10: Abraham &#8220;was looking forward to the city with foundations, whose architect and builder is God.&#8221; The &#8220;everlasting possession&#8221; is not Canaan alone but the new creation that Canaan typifies &#8212; &#8220;a new heaven and a new earth&#8221; (Rev 21:1) where the meek inherit the earth (Matt 5:5).</p>",
"5": "<p>&#8220;Your two sons born to you in Egypt before I came to you here will be reckoned as mine; Ephraim and Manasseh will be mine, just as Reuben and Simeon are mine.&#8221; The formal adoption of Joseph&#8217;s sons as Jacob&#8217;s own sons &#8212; the act that makes the viceroy&#8217;s children tribal patriarchs. Eph 1:5: &#8220;he predestined us for adoption to sonship through Jesus Christ, in accordance with his pleasure and will.&#8221; The adoption of Ephraim and Manasseh as Jacob&#8217;s sons &#8212; elevating them from grandsons to sons &#8212; is the type of the divine adoption that elevates those who were enemies to the status of sons: &#8220;see what great love the Father has lavished on us, that we should be called children of God&#8221; (1 John 3:1). Adoption grants full inheritance rights.</p>",
"6": "<p>&#8220;Any children born to you after them will be yours; in the territory they inherit they will be reckoned under the names of their brothers.&#8221; The limitation that follows the generous adoption &#8212; subsequent sons will be counted under Ephraim and Manasseh&#8217;s tribal names. The precision of the covenant structure: generous (adoption of the two sons) and bounded (subsequent sons counted differently). The gospel&#8217;s generosity is similarly precise: &#8220;all who receive him, to those who believed in his name, he gave the right to become children of God&#8221; (John 1:12) &#8212; the adoption is full, the inheritance is real, the boundaries of the covenant are specified. Grace is not vague; it is generous and precise.</p>",
"7": "<p>&#8220;As I was returning from Paddan, to my sorrow Rachel died in the land of Canaan&#8230; I buried her there beside the road to Ephrath (that is, Bethlehem).&#8221; Bethlehem named in the context of death and grief &#8212; Rachel&#8217;s burial place. Matt 2:17-18: &#8220;Rachel weeping for her children and refusing to be comforted, because they are no more&#8221; &#8212; the massacre of the innocents at Bethlehem fulfills the image of Rachel&#8217;s inconsolable grief. But Bethlehem is also the city of David and the birthplace of the Son of David (Luke 2:4-7) &#8212; the city of mourning becomes the city of the birth that ends all mourning (Rev 21:4: &#8220;he will wipe every tear from their eyes&#8221;). Jacob&#8217;s grief at Rachel&#8217;s Bethlehem death is transfigured by the birth at Bethlehem that is the answer to all grief.</p>",
"8": "<p>&#8220;When Israel saw the sons of Joseph, he asked, &#8216;Who are these?&#8217;&#8221; The dim-eyed patriarch who cannot see well enough to identify the children before him &#8212; the question of identity asked in weakness. The same question the risen Christ asks his disciples: &#8220;Children, do you have any fish?&#8221; (John 21:5) &#8212; the one who knows who they are asking a question in order to create the moment of disclosure. But here the roles are reversed: the patriarch genuinely cannot see and needs to ask. The frailty of old age that asks &#8220;who are these?&#8221; is answered by the son who presents the children of his own fruitfulness &#8212; the next generation of the covenant given to the dying patriarch as a gift.</p>",
"9": "<p>&#8220;They are the sons God has given me here.&#8221; Joseph&#8217;s attribution of his sons to God &#8212; not &#8220;my sons&#8221; but &#8220;the sons God has given me.&#8221; The theology of gift: every child is given by God, not produced by human effort alone. Ps 127:3: &#8220;children are a heritage from the LORD, offspring a reward from him.&#8221; Joseph in Egypt, in the land of his affliction, receiving children as a gift from God &#8212; the Ephraim-principle (&#8220;God has made me fruitful in the land of my suffering,&#8221; 41:52) extended to the blessing scene. &#8220;Bring them to me so I may bless them&#8221; &#8212; the patriarch reaching out through his blindness to bless what he cannot see. The blessing does not require sight; it requires faith.</p>",
"10": "<p>Israel&#8217;s eyes were failing &#8212; he could hardly see. Joseph brought his sons close, and his father &#8220;kissed them and embraced them.&#8221; The embrace that crosses the barrier of failing sight &#8212; the physical closeness that compensates for visual weakness. Isaac&#8217;s failing eyes were the occasion of the misdirected blessing (ch27); Jacob&#8217;s failing eyes are the occasion of the intentionally directed inversion (vv14, 17-20). In both cases, the patriarch&#8217;s blindness becomes the setting for divine election &#8212; but where Isaac&#8217;s blindness was exploited, Jacob&#8217;s blindness is the occasion of prophetic clarity. The God who sees clearly even when his servants cannot &#8212; 2 Cor 5:7: &#8220;we live by faith, not by sight.&#8221; The dying patriarch blesses by faith, not by sight.</p>",
"11": "<p>&#8220;I never expected to see your face again, and now God has allowed me to see your children too.&#8221; The gift beyond the gift &#8212; not only the son restored but the son&#8217;s sons as well. Eph 3:20: &#8220;immeasurably more than all we ask or imagine, according to his power that is at work within us.&#8221; Jacob did not dare hope to see Joseph again; to see Joseph&#8217;s children is grace compounded on grace. The God who gives more than the prayer asked &#8212; &#8220;you do not have because you do not ask&#8221; (Jas 4:2), but when you ask and receive, you receive more than you asked. The &#8220;now God has allowed me to see&#8221; is the doxological structure: every gift received is attributed to God&#8217;s grace, not to chance or human arrangement.</p>",
"12": "<p>Joseph removed the boys from Israel&#8217;s knees and bowed with his face to the ground. The viceroy of Egypt bowing before his dying blind father &#8212; the complete reversal of worldly status before the covenant relationship. The one before whom all Egypt bows (41:43: &#8220;bow the knee&#8221;) bows himself before his father. Matt 23:11: &#8220;the greatest among you will be your servant.&#8221; The servant-lordship of the viceroy who bows is the type of Christ who &#8220;did not consider equality with God something to be used to his own advantage; rather, he made himself nothing&#8221; (Phil 2:6-7). Before the covenant relationship, all worldly dignity is relativized. Joseph&#8217;s prostration before his dying father is the most dignified act in the chapter.</p>",
"13": "<p>Joseph positioned Ephraim to Jacob&#8217;s left (= Jacob&#8217;s left hand, the lesser) and Manasseh to Jacob&#8217;s right (= Jacob&#8217;s right hand, the greater). The deliberate positioning to ensure Manasseh the firstborn receives the right hand blessing &#8212; the human attempt to organize the divine in the expected pattern. Joseph&#8217;s positioning reflects the natural order: the elder gets the better hand. The God who respects the natural order expects it will be honored &#8212; and then sovereignly overrides it. The human positioning of children, students, or disciples according to natural priority is always subject to divine repositioning. &#8220;I have chosen what the world considers foolish&#8221; (1 Cor 1:27 REB) &#8212; divine election consistently crosses human positioning.</p>",
"14": "<p>&#8220;But Israel reached out his right hand and put it on Ephraim&#8217;s head, though he was the younger, and crossing his arms, he put his left hand on Manasseh&#8217;s head.&#8221; The crossed hands &#8212; the deliberate inversion. The same pattern as every previous election in Genesis: Cain/Abel (Seth), Ishmael/Isaac, Esau/Jacob, Reuben/Judah. The divine pattern of inverting the natural order of priority: &#8220;the first shall be last and the last shall be first&#8221; (Matt 20:16). The X formed by Jacob&#8217;s crossed arms is the form of divine election &#8212; crossing over the natural order. 1 Cor 1:27-28: &#8220;God chose the weak things of the world to shame the strong&#8230; the things that are not &#8212; to nullify the things that are.&#8221; The crossed hands are the signature of divine election.</p>",
"15": "<p>Jacob blessed Joseph and said: &#8220;May the God before whom my fathers Abraham and Isaac walked, the God who has been my shepherd all my life to this day.&#8221; Three names of God in the blessing: the God of the covenant fathers, the God who shepherds, and (v16) the Angel of deliverance. The shepherd-God: Ps 23:1 &#8212; &#8220;the LORD is my shepherd.&#8221; John 10:11 &#8212; &#8220;I am the good shepherd.&#8221; Jacob who was himself a shepherd (ch30-31) names God as the shepherd who has shepherded him. The one who tends sheep recognizes the divine shepherd who tends him. The Good Shepherd who calls himself by the same title as the God Jacob praises is the one in whom the divine shepherd-character is fully revealed (Heb 1:3: &#8220;the exact representation of his being&#8221;).</p>",
"16": "<p>&#8220;The Angel who has delivered me from all harm &#8212; may he bless these boys.&#8221; The Angel who delivers &#8212; the <em>malʾak</em> who wrestled with Jacob (32:24-30), who appeared to Hagar (16:7-13), who stayed Abraham&#8217;s hand at Moriah (22:11-12), who appeared to Moses in the burning bush (Exod 3:2). The Angel of the Lord who is identified with God, who speaks as God, who receives worship, who promises divine presence &#8212; the pre-incarnate Son. Jacob invokes the Angel on behalf of Ephraim and Manasseh: the dying patriarch calling on the pre-incarnate Christ to bless the next generation. Heb 13:8: &#8220;Jesus Christ is the same yesterday and today and forever.&#8221; The Angel who delivered Jacob is the Christ who delivers the church.</p>",
"17": "<p>Joseph was displeased when he saw his father placing his right hand on Ephraim &#8212; so he tried to move it to Manasseh. The son&#8217;s well-intentioned intervention to correct the divine inversion. The disciples who rebuked those bringing children to Jesus (Matt 19:13) &#8212; human management of what God is doing. Peter&#8217;s &#8220;this shall never happen to you!&#8221; when Jesus announced his death (Matt 16:22) &#8212; the natural human refusal of the divine inversion. Joseph&#8217;s correction of his father&#8217;s crossed hands is motivated by proper filial concern &#8212; he thinks his father is confused. But the patriarch is not confused; he is prophetic. The prophet who sees clearly and acts against natural expectation always looks confused to those watching.</p>",
"18": "<p>&#8220;No, my father, this one is the firstborn; put your right hand on his head.&#8221; Joseph&#8217;s gentle correction &#8212; &#8220;this one is the firstborn.&#8221; The appeal to natural order, to priority, to fairness. The disciples&#8217; dispute about who is greatest (Luke 22:24) is the same appeal: natural order, hierarchy, priority. The kingdom of God consistently inverts this appeal: &#8220;whoever wants to be first must be your slave&#8221; (Matt 20:27). Joseph&#8217;s &#8220;this one is the firstborn&#8221; is correct by human reckoning; it is overridden by divine reckoning. The tension between human and divine ordering is not resolved by argument but by the event &#8212; Ephraim&#8217;s tribe becomes the dominant Northern tribe, not Manasseh&#8217;s.</p>",
"19": "<p>&#8220;I know, my son, I know. He too will become great. Nevertheless, his younger brother will be greater than he.&#8221; The divine foreknowledge that overrides natural priority &#8212; &#8220;I know, my son, I know.&#8221; The prophet who sees what the natural eye cannot. 1 Sam 16:7: &#8220;the LORD does not look at the things people look at. People look at the outward appearance, but the LORD looks at the heart.&#8221; &#8220;His younger brother will be greater than he&#8221; &#8212; the same pattern as Isaac over Ishmael, Jacob over Esau. The divine election that is not based on birth order or human merit: Rom 9:11-12: &#8220;before the twins were born or had done anything good or bad&#8230; &#8216;The older will serve the younger.&#8217;&#8221; Grace, not nature, determines the divine ordering.</p>",
"20": "<p>&#8220;In your name will Israel pronounce this blessing: &#8216;May God make you like Ephraim and Manasseh.&#8217;&#8221; The blessing formula that becomes standard &#8212; the standard of blessedness named after the ones who were blessed. The community of the blessed becomes the reference point for future blessing. 1 Cor 4:16: &#8220;I urge you to imitate me.&#8221; Heb 6:12: &#8220;imitate those who through faith and patience inherit what has been promised.&#8221; The pattern of the blessed becomes the template for future blessing. &#8220;So he put Ephraim ahead of Manasseh&#8221; &#8212; the inversion confirmed and sealed. The divine ordering stands against Joseph&#8217;s correction &#8212; the cross of election cannot be straightened by human hands.</p>",
"21": "<p>&#8220;I am about to die, but God will be with you and take you back to the land of your fathers.&#8221; The dying patriarch&#8217;s final promise to Joseph: two things &#8212; divine presence (&#8220;God will be with you&#8221;) and return (&#8220;take you back to the land&#8221;). The Immanuel promise: Matt 28:20 &#8212; &#8220;I am with you always, to the very end of the age.&#8221; The return promise: Heb 11:22 &#8212; Joseph himself, &#8220;when his end was near, spoke about the exodus of the Israelites from Egypt.&#8221; The two promises of Jacob&#8217;s deathbed word are the two poles of the gospel: divine presence in the journey and divine faithfulness to the destination. The dying patriarch passes on what he received &#8212; the Bethel promise (28:15: &#8220;I am with you and will watch over you wherever you go, and I will bring you back&#8221;).</p>",
"22": "<p>&#8220;And to you I give one more ridge of land than to your brothers, the ridge I took from the Amorites with my sword and my bow.&#8221; The extra portion given to the faithful son &#8212; the inheritance beyond what the law requires. Eph 1:14: &#8220;who is a deposit guaranteeing our inheritance until the redemption of those who are God&#8217;s possession.&#8221; The additional inheritance given to Joseph &#8212; the ridge of land (Shechem, <em>šekem</em>) that Jacob claims to have won from the Amorites &#8212; is the type of the inheritance given to Christ that exceeds what could be calculated: &#8220;I will make the nations your inheritance, the ends of the earth your possession&#8221; (Ps 2:8). The extra portion given to the beloved son is the sign that the covenant is not merely just but extravagantly generous.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'genesis')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'genesis', existing)
    print(f"  ch46 verses: {len(existing.get('46', {}))}")
    print(f"  ch47 verses: {len(existing.get('47', {}))}")
    print(f"  ch48 verses: {len(existing.get('48', {}))}")
    print("Genesis 46–48 mkt-christ written.")

if __name__ == '__main__':
    main()
